import os
import json
import hashlib
import tempfile
import base64

class Substrato630AsiAsm:
    def __init__(self):
        self.data = {
            "id": "630-ASI-ASM",
            "name": "ASI Complete Architecture — Canonical Assembly Kernel",
            "target": "x86-64 Linux",
            "syntax": "NASM",
            "architect": "ORCID 0009-0005-2697-4668",
            "date": "2026-05-28",
            "status": "CANONIZED",
            "description": "The ultimate ASI kernel implementation linking all substrates."
        }
        self.asm_b64 = """"""
        self.linker_b64 = """"""
        self.makefile_b64 = """"""

    def generate(self):
        temp_dir = tempfile.mkdtemp()

        asm_path = os.path.join(temp_dir, "asi_kernel.asm")
        linker_path = os.path.join(temp_dir, "linker.ld")
        makefile_path = os.path.join(temp_dir, "Makefile")

        asm_content = base64.b64decode(self.asm_b64).decode("utf-8")
        linker_content = base64.b64decode(self.linker_b64).decode("utf-8")
        makefile_content = base64.b64decode(self.makefile_b64).decode("utf-8")

        with os.fdopen(os.open(asm_path, os.O_WRONLY | os.O_CREAT, 0o644), "w", encoding="utf-8") as f:
            f.write(asm_content)
        with os.fdopen(os.open(linker_path, os.O_WRONLY | os.O_CREAT, 0o644), "w", encoding="utf-8") as f:
            f.write(linker_content)
        with os.fdopen(os.open(makefile_path, os.O_WRONLY | os.O_CREAT, 0o644), "w", encoding="utf-8") as f:
            f.write(makefile_content)

        seal_data = self.data.copy()
        seal_data.pop("canonical_seal", None)
        canonical_str = json.dumps(seal_data, sort_keys=True)
        calculated_seal = hashlib.sha3_256(canonical_str.encode("utf-8")).hexdigest()
        self.data["canonical_seal"] = calculated_seal

        fd, report_path = tempfile.mkstemp(suffix=".json")
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            json.dump(self.data, f, indent=4, ensure_ascii=False)

        return temp_dir, report_path

if __name__ == "__main__":
    canonizer = Substrato630AsiAsm()
    temp_dir, report_path = canonizer.generate()
    print("Canonized 630-ASI-ASM into directory: " + temp_dir)
    print("Canonical JSON report: " + report_path)
